#include<bits/stdc++.h>
using namespace std;
int fail[10000010],son[10000010][31],cnt[10000010],tot;
string s[100010];
bool vis[1000010];
void insert(string s)
{
    int p=0,len=s.size();
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'A';
        if(!son[p][x])
        {
            son[p][x]=++tot;
        }
        p=son[p][x];
    }
    cnt[p]++;
}
void getfail()
{
    queue<int> q;
    for(int i=0;i<26;i++)
    {
        if(son[0][i])
        {
            fail[son[0][i]]=0;
            q.push(son[0][i]);
        }
    }
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i=0;i<26;i++)
        {
            if(son[t][i])
            {
                fail[son[t][i]]=son[fail[t]][i];
                q.push(son[t][i]);
            }
            else
            {
                son[t][i]=son[fail[t]][i];
            }
        }
    }
}
void update(string s)
{
    int len=s.size();
    int p=0;
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'A';
        p=son[p][x];
        for(int t=p;t!=0&&!vis[t];t=fail[t])
        {
            vis[t]=true;
        }
    }
}
int query(string s)
{
    int p=0,len=s.length(),ans=0;
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'A';
        p=son[p][x];
        if(vis[p])
        {
            ans=i+1;
        }
    }
    return ans;
}
int main()
{
    int len;
    int n;
    scanf("%d%d",&len,&n);
    string str;
    cin>>str;
    for(int i=1;i<=n;i++)
    {
        cin>>s[i];
        insert(s[i]);
    }
    getfail();
    update(str);
    for(int i=1;i<=n;i++)
    {
        printf("%d\n",query(s[i]));
    }
    return 0;
}
